function updateMenuDuJour() {
  const now = new Date();
  const day = now.getDay(); // 0=dimanche
  const menu = menusAfricains[day];
  // Jours en français
  const jours = ["Dimanche","Lundi","Mardi","Mercredi","Jeudi","Vendredi","Samedi"];
  const mois = ["janvier","février","mars","avril","mai","juin","juillet","août","septembre","octobre","novembre","décembre"];
  const dateStr = jours[day] + " " + now.getDate() + " " + mois[now.getMonth()] + " " + now.getFullYear();
  const set = (id, val) => { const el = document.getElementById(id); if(el) el.textContent = val; };
  const setHtml = (id, val) => { const el = document.getElementById(id); if(el) el.innerHTML = val; };
  set("menuDate", "📅 " + dateStr);
  set("menuPdejEmoji", menu.pdej.emoji);
  set("menuPdejPlat", menu.pdej.plat);
  set("menuPdejDesc", menu.pdej.desc);
  set("menuPdejTag", menu.pdej.tag);
  set("menuDejEmoji", menu.dej.emoji);
  set("menuDejPlat", menu.dej.plat);
  set("menuDejDesc", menu.dej.desc);
  set("menuDejTag", menu.dej.tag);
  set("menuDinerEmoji", menu.diner.emoji);
  set("menuDinerPlat", menu.diner.plat);
  set("menuDinerDesc", menu.diner.desc);
  set("menuDinerTag", menu.diner.tag);
  set("menuAstuce", menu.astuce);
}
function updateMenuCountdown() {
  const now = new Date();
  const midnight = new Date();
  midnight.setHours(24, 0, 0, 0);
  const diff = midnight - now;
  const h = Math.floor(diff / 3600000);
  const m = Math.floor((diff % 3600000) / 60000);
  const s = Math.floor((diff % 60000) / 1000);
  const pad = n => String(n).padStart(2, "0");
  const el = document.getElementById("menuCountdown");
  if(el) el.textContent = pad(h) + "h " + pad(m) + "m " + pad(s) + "s";
}
updateMenuDuJour();
updateMenuCountdown();
setInterval(updateMenuCountdown, 1000);


