// Countdown plat du jour (expire à 20h)
function updatePlatJourCountdown() {
  const now = new Date();
  const target = new Date();
  target.setHours(20, 0, 0, 0);
  if (now >= target) target.setDate(target.getDate() + 1);
  const diff = target - now;
  const h = Math.floor(diff / 3600000);
  const m = Math.floor((diff % 3600000) / 60000);
  const s = Math.floor((diff % 60000) / 1000);
  const pad = n => String(n).padStart(2, "0");
  const pH = document.getElementById("pcdH");
  const pM = document.getElementById("pcdM");
  const pS = document.getElementById("pcdS");
  if (pH) pH.textContent = pad(h);
  if (pM) pM.textContent = pad(m);
  if (pS) pS.textContent = pad(s);
}
updatePlatJourCountdown();
setInterval(updatePlatJourCountdown, 1000);


