// ── PANIER PERSISTANT ──
const CART_KEY = "olaprestige_cart";
function loadCart() { try { return JSON.parse(localStorage.getItem(CART_KEY)||'{}'); } catch(e){ return {}; } }
function saveCart() { try { localStorage.setItem(CART_KEY, JSON.stringify(cart)); } catch(e){} }
let cart = loadCart();
// Debounce updateCart pour éviter re-renders multiples
let _cartRafId = null;
function scheduleCartUpdate() {
  if(_cartRafId) return;
  _cartRafId = requestAnimationFrame(() => { _cartRafId = null; updateCart(); });
}
function renderProducts() {
  const urgencyLabels = ["🔥 Populaire", "⚡ Rapide", "❤️ Favori", "✨ Top vente", "🏆 N°1", "🌿 Bio", "👑 Premium"];
  const grid = document.getElementById("productsGrid");
  grid.innerHTML = products.map((p, idx) => `
    <div class="card" onclick="openModal(${p.id})">
      <div class="card-img-wrap">
        <img class="card-img" src="${p.img}" alt="${p.name}" loading="lazy"/>
        <span class="card-badge">${p.badge}</span>
        <span class="card-urgency-badge">${urgencyLabels[idx % urgencyLabels.length]}</span>
      </div>
      <div class="card-body">
        <div class="card-name">${p.name}</div>
        <div class="card-desc">${p.desc}</div>
        <div class="card-footer">
          <div class="card-price">
            ${p.price.toLocaleString()} FCFA
            <small>/ ${p.unit}</small>
          </div>
          <div class="card-actions">
            <button class="add-btn" onclick="event.stopPropagation();addToCart(${p.id})">🛒 +</button>
            <button class="quick-wa-btn" onclick="event.stopPropagation();quickOrder(${p.id})">📲 Commander</button>
          </div>
        </div>
      </div>
    </div>
  `).join("");
}
function quickOrder(id) {
  const p = products.find(x => x.id === id);
  if (!p) return;
  if (window.navigator && window.navigator.vibrate) window.navigator.vibrate(25);
  const msg = `Bonjour OlaPrestige ! Je souhaite commander en express : ${p.name} 🍽️`;
  window.open(`https://wa.me/${WA_NUMBER}?text=${encodeURIComponent(msg)}`, "_blank");
}
function addToCart(id, option) {
  const key = option ? id + '_' + option.replace(/\s+/g,'_') : id;
  if(!cart[key]) cart[key] = {id, qty:0, option: option||null};
  cart[key].qty++;
  saveCart();
  scheduleCartUpdate();
  const p = products.find(x=>x.id===id);
  if (window.navigator && window.navigator.vibrate) window.navigator.vibrate(20);
  showToast(`✦ ${p.name} ajouté au panier ! 🍽️`);
}
function removeFromCart(id) { delete cart[id]; saveCart(); scheduleCartUpdate(); }
function changeQty(id, delta) {
  if (!cart[id]) return;
  if (typeof cart[id] === 'number') {
    cart[id] += delta;
    if (cart[id] <= 0) delete cart[id];
  } else {
    cart[id].qty += delta;
    if (cart[id].qty <= 0) delete cart[id];
  }
  saveCart();
  scheduleCartUpdate();
}
function updateCart() {
  // Normalize cart entries (support legacy number format + new object format)
  const entries = Object.entries(cart).map(([key, val]) => {
    if(typeof val === 'number') return {key, id: parseInt(key), qty: val, option: null};
    return {key, id: val.id, qty: val.qty, option: val.option};
  }).filter(e => e.qty > 0);
  const subTotal = entries.reduce((s,e) => {
    const p = products.find(p => p.id == e.id);
    let price = p ? p.price : 0;
    if (e.option && e.option.includes("(+")) {
      const match = e.option.match(/\(\+(\d+)/);
      if (match) price += parseInt(match[1]);
    }
    return s + (price * e.qty);
  }, 0);
  const total = subTotal + DELIVERY_FEE;
  const count = entries.reduce((s,e) => s + e.qty, 0);
  document.getElementById("cartCount").textContent = count;
  const countEl = document.getElementById("cartCount");
  countEl.textContent = count;
  countEl.classList.remove("bump");
  void countEl.offsetWidth; // reflow
  if(count > 0) countEl.classList.add("bump");
  const mob = document.getElementById("mobCartLabel");
  if(mob) mob.textContent = count > 0 ? `Panier (${count})` : "Panier";
  const pulse = document.getElementById("mobCartPulse");
  if(pulse) pulse.classList.toggle("active", count > 0);
  const itemsEl = document.getElementById("cartItems");
  const footerEl = document.getElementById("cartFooter");
  if(!count) {
    itemsEl.innerHTML = `<div class="cart-empty">Votre panier est vide ✦</div>`;
    footerEl.style.display = "none";
    return;
  }
  footerEl.style.display = "block";
  document.getElementById("subTotalPrice").textContent = subTotal.toLocaleString() + " FCFA";
  document.getElementById("totalPrice").textContent = total.toLocaleString() + " FCFA";
  itemsEl.innerHTML = entries.map(e => {
    const p = products.find(x => x.id == e.id);
    if(!p) return '';
    let itemPrice = p.price;
    if (e.option && e.option.includes("(+")) {
      const match = e.option.match(/\(\+(\d+)/);
      if (match) itemPrice += parseInt(match[1]);
    }
    return `<div class="cart-item">
      <img src="${p.img}" alt="${p.name}" loading="lazy"/>
      <div class="cart-item-info">
        <div class="cart-item-name">${p.name}${e.option ? ` <span style="font-size:.7rem;color:var(--gold);font-weight:700;">(${e.option})</span>` : ''}</div>
        <div class="cart-item-price">${(itemPrice * e.qty).toLocaleString()} FCFA</div>
        <div class="qty-ctrl">
          <button class="qty-btn" onclick="changeQty('${e.key}',-1)">−</button>
          <span class="qty-num">${e.qty}</span>
          <button class="qty-btn" onclick="changeQty('${e.key}',1)">+</button>
        </div>
      </div>
      <button class="remove-btn" onclick="removeFromCart('${e.key}')">🗑</button>
    </div>`;
  }).join("");
}
function toggleCart() {
  document.getElementById("cartOverlay").classList.toggle("open");
  document.getElementById("cartPanel").classList.toggle("open");
}
let modalProductId=null, modalQty=1;
function openModal(id) {
  const p=products.find(x=>x.id===id);
  const d=productDetails[id];
  modalProductId=id; modalQty=1;
  document.getElementById("modalImg").src=p.img;
  document.getElementById("modalBadge").textContent=p.badge;
  document.getElementById("modalCategory").textContent=p.badge.toUpperCase();
  document.getElementById("modalName").textContent=p.name;
  document.getElementById("modalPrice").innerHTML=`${p.price.toLocaleString()} FCFA <small>/ ${p.unit}</small>`;
  document.getElementById("modalDesc").textContent=d.fullDesc;
  document.getElementById("modalTags").innerHTML=d.tags.map(t=>`<span class="tag">${t}</span>`).join("");
  document.getElementById("modalQtyDisplay").textContent=1;
  document.getElementById("modalSubtotal").textContent=`= ${p.price.toLocaleString()} FCFA`;
  document.getElementById("similarGrid").innerHTML=products.filter(x=>x.id!==id).slice(0,3).map(s=>`
    <div class="similar-card" onclick="openModal(${s.id})">
      <img src="${s.img}" alt="${s.name}" loading="lazy"/>
      <div class="similar-card-name">${s.name}</div>
      <div class="similar-card-price">${s.price.toLocaleString()} FCFA</div>
    </div>`).join("");
  // ── INGRÉDIENTS ──
  const ingWrap = document.getElementById('modalIngredients');
  const ingList = document.getElementById('ingredientsList');
  if(p.ingredients && p.ingredients.length > 0) {
    ingList.innerHTML = p.ingredients.map(i => `<span class="ingredient-tag">🌿 ${i}</span>`).join('');
    ingWrap.style.display = 'block';
  } else {
    ingWrap.style.display = 'none';
  }
  // ── OPTIONS PERSONNALISATION ──
  const optWrap = document.getElementById('modalOptions');
  const optGrid = document.getElementById('optionsGrid');
  const optLabel = document.getElementById('optionLabel');
  window._selectedOption = null;
  if(p.options && p.options.length > 0) {
    if(optLabel) optLabel.textContent = '🎛️ ' + (p.optionLabel || 'Option');
    optGrid.innerHTML = p.options.map((o,i) =>
      `<button class="option-btn${i===0?' selected':''}" onclick="selectOption(this,'${o}')">${o}</button>`
    ).join('');
    window._selectedOption = p.options[0];
    optWrap.style.display = 'block';
  } else {
    optWrap.style.display = 'none';
  }
  document.getElementById("modalOverlay").classList.add("open");
  document.body.style.overflow="hidden";
}
function selectOption(btn, value) {
  if (window.event) {
    window.event.preventDefault();
    window.event.stopPropagation();
  }
  document.querySelectorAll('.option-btn').forEach(b => b.classList.remove('selected'));
  btn.classList.add('selected');
  window._selectedOption = value;
}
function closeModal() { document.getElementById("modalOverlay").classList.remove("open"); document.body.style.overflow=""; }
function handleOverlayClick(e) { if(e.target===document.getElementById("modalOverlay")) closeModal(); }
function modalQtyChange(delta) {
  modalQty=Math.max(1,modalQty+delta);
  document.getElementById("modalQtyDisplay").textContent=modalQty;
  const p=products.find(x=>x.id===modalProductId);
  document.getElementById("modalSubtotal").textContent=`= ${(p.price*modalQty).toLocaleString()} FCFA`;
}
function addFromModal() {
  const p = products.find(x => x.id === modalProductId);
  const option = window._selectedOption || null;
  const key = option ? modalProductId + '_' + option.replace(/\s+/g, '_') : modalProductId;
  if (!cart[key]) {
    cart[key] = { id: modalProductId, qty: 0, option: option };
  }
  if (typeof cart[key] === 'number') {
    // Conversion si l'ancien format est présent
    cart[key] = { id: modalProductId, qty: cart[key] + modalQty, option: option };
  } else {
    cart[key].qty += modalQty;
  }
  updateCart();
  saveCart();
  showToast(`✦ ${modalQty}× ${p.name} ajouté !`);
  closeModal();
}
function openOrderModal() {
  const count=Object.values(cart).reduce((s,q)=>s+q,0);
  if(!count){ showToast("🛒 Ajoutez d'abord des produits !"); return; }
  updateOrderSummary();
  document.getElementById("cartOverlay").classList.remove("open");
  document.getElementById("cartPanel").classList.remove("open");
  document.getElementById("orderOverlay").classList.add("open");
  document.body.style.overflow="hidden";
  document.getElementById("orderMode").onchange=updateOrderSummary;
}
function updateOrderSummary() {
  const mode=document.getElementById("orderMode").value;
  const fee=mode==="retrait"?0:DELIVERY_FEE;
  const subTotal=Object.entries(cart).reduce((s,[id,qty])=>s+products.find(p=>p.id==id).price*qty,0);
  const total=subTotal+fee;
  document.getElementById("orderSummaryItems").innerHTML=Object.entries(cart).map(([id,qty])=>{
    const p=products.find(x=>x.id==id);
    return `<div class="order-item-row"><span>${p.name} × ${qty}</span><span>${(p.price*qty).toLocaleString()} FCFA</span></div>`;
  }).join("");
  document.getElementById("orderDeliveryFee").textContent=fee>0?`${fee.toLocaleString()} FCFA`:"Gratuit 🎉";
  document.getElementById("orderTotalDisplay").textContent=total.toLocaleString()+" FCFA";
}
function closeOrderModal() { document.getElementById("orderOverlay").classList.remove("open"); document.body.style.overflow=""; }
function handleOrderOverlay(e) { if(e.target===document.getElementById("orderOverlay")) closeOrderModal(); }
// ── ENVOI DIRECT DEPUIS LE PANIER (sans modal) ──
function sendWhatsAppDirect() {
  const nomComplet = document.getElementById("cartNomComplet").value.trim();
  const tel        = document.getElementById("cartTel").value.trim();
  const quartier   = document.getElementById("cartQuartier").value;
  // Réinitialiser les erreurs visuelles
  ["fieldNomComplet","fieldTelComplet","fieldQuartier"].forEach(id => {
    document.getElementById(id).classList.remove("cart-field-error");
  });
  const form = document.getElementById("cartUserInfo");
  form.classList.remove("error-shake");
  // Validation
  let hasError = false;
  if(!nomComplet){ document.getElementById("fieldNomComplet").classList.add("cart-field-error"); hasError=true; }
  if(!tel){        document.getElementById("fieldTelComplet").classList.add("cart-field-error"); hasError=true; }
  if(!quartier){   document.getElementById("fieldQuartier").classList.add("cart-field-error"); hasError=true; }
  if(hasError){
    // Animation shake sur le formulaire
    void form.offsetWidth; // reflow pour relancer l'animation
    form.classList.add("error-shake");
    setTimeout(()=>form.classList.remove("error-shake"), 500);
    showToast("\u26a0\ufe0f Veuillez remplir tous vos infos de livraison.");
    return;
  }
  // Calcul du total
  const subTotal = Object.entries(cart).reduce((s, [key, val]) => {
    const id = typeof val === 'number' ? parseInt(key) : val.id;
    const qty = typeof val === 'number' ? val : val.qty;
    const option = typeof val === 'number' ? null : val.option;
    const p = products.find(x => x.id == id);
    let price = p ? p.price : 0;
    if (option && option.includes("(+")) {
      const match = option.match(/\(\+(\d+)/);
      if (match) price += parseInt(match[1]);
    }
    return s + (price * qty);
  }, 0);
  const total = subTotal + DELIVERY_FEE;
  // Construction du message WhatsApp formaté
  let lignesCommande = "";
  Object.entries(cart).forEach(([key, val]) => {
    const id = typeof val === 'number' ? parseInt(key) : val.id;
    const qty = typeof val === 'number' ? val : val.qty;
    const option = typeof val === 'number' ? null : val.option;
    const p = products.find(x => x.id == id);
    if (p) {
      let price = p.price;
      if (option && option.includes("(+")) {
        const match = option.match(/\(\+(\d+)/);
        if (match) price += parseInt(match[1]);
      }
      lignesCommande += `- ${qty}x ${p.name}${option ? ` (${option})` : ''} (${(price * qty).toLocaleString()} FCFA)\n`;
    }
  });
  const msg =
`Bonjour OlaPrestige, voici ma commande :
${lignesCommande}
Total Commande : ${total.toLocaleString()} FCFA
--- Infos de Livraison ---
Nom : ${nomComplet}
T\u00e9l : ${tel}
Livraison : ${quartier}, Cotonou`;
  window.open(`https://wa.me/${WA_NUMBER}?text=${encodeURIComponent(msg)}`,"_blank");
  // Réinitialiser le panier et le formulaire
  cart = {};
  saveCart();
  updateCart();
  document.getElementById("cartNomComplet").value = "";
  document.getElementById("cartTel").value = "";
  document.getElementById("cartQuartier").value = "";
  if(window.trackCommande) window.trackCommande();
  showToast("\u2705 Redirection vers WhatsApp !");
}
function sendWhatsApp() {
  const prenom=document.getElementById("orderPrenom").value.trim();
  const nom=document.getElementById("orderNom").value.trim();
  const tel=document.getElementById("orderTel").value.trim();
  const adresse=document.getElementById("orderAdresse").value.trim();
  const mode=document.getElementById("orderMode").value;
  const note=document.getElementById("orderNote").value.trim();
  if(!prenom||!nom||!tel||!adresse){ showToast("⚠️ Remplissez tous les champs obligatoires."); return; }
  const modeLabel=mode==="livraison"?"🚚 Livraison à domicile":"🏃 Retrait sur place";
  const fee=mode==="retrait"?0:DELIVERY_FEE;
  const subTotal = Object.entries(cart).reduce((s, [key, val]) => {
    const id = typeof val === 'number' ? parseInt(key) : val.id;
    const qty = typeof val === 'number' ? val : val.qty;
    const p = products.find(x => x.id == id);
    return s + (p ? p.price * qty : 0);
  }, 0);
  const total=subTotal+fee;
  let msg=`✦ NOUVELLE COMMANDE — OlaPrestige ✦\n\n`;
  msg+=`👤 Client : ${prenom} ${nom}\n📞 Tél : ${tel}\n📍 Adresse : ${adresse}\n📦 Mode : ${modeLabel}\n\n🛒 Commande :\n`;
  Object.entries(cart).forEach(([key, val]) => {
    const id = typeof val === 'number' ? parseInt(key) : val.id;
    const qty = typeof val === 'number' ? val : val.qty;
    const option = typeof val === 'number' ? null : val.option;
    const p = products.find(x => x.id == id);
    if (p) {
      msg += `  • ${p.name}${option ? ` (${option})` : ''} × ${qty} = ${(p.price * qty).toLocaleString()} FCFA\n`;
    }
  });
  msg+=`\n🚚 Livraison : ${fee>0?fee.toLocaleString()+' FCFA':'Gratuit'}`;
  msg+=`\n💰 TOTAL : ${total.toLocaleString()} FCFA`;
  if(note) msg+=`\n\n📝 Note : ${note}`;
  window.open(`https://wa.me/${WA_NUMBER}?text=${encodeURIComponent(msg)}`,"_blank");
  closeOrderModal();
  cart = {};
  saveCart();
  updateCart();
  // Tracker la commande dans Firebase
  if(window.trackCommande) window.trackCommande();
  showToast("✅ Redirection vers WhatsApp !");
}
