function updateStatus() {
  const now = new Date();
  const day = now.getDay();
  const h = now.getHours();
  const m = now.getMinutes();
  const time = h * 60 + m;
  let open = false;
  if(day >= 1 && day <= 6) open = time >= 9*60 && time < 20*60;
  if(day === 0) open = time >= 10*60 && time < 20*60;
  const el = document.getElementById('openStatus');
  if(el) {
    el.textContent = open ? '🟢 Ouvert' : '🔴 Fermé';
    el.style.color = open ? '#4ade80' : '#f87171';
  }
}
updateStatus();
setInterval(updateStatus, 60000);
// ── COUNTDOWN — rAF pour 60fps smooth sans surcharge ──
let _lastCountdownSec = -1;
function updateCountdown() {
  const now = new Date();
  const target = new Date();
  target.setHours(12, 0, 0, 0);
  if(now >= target) target.setDate(target.getDate() + 1);
  const diff = target - now;
  const totalSec = Math.floor(diff / 1000);
  if(totalSec === _lastCountdownSec) { requestAnimationFrame(updateCountdown); return; }
  _lastCountdownSec = totalSec;
  const h = Math.floor(diff / 3600000);
  const m = Math.floor((diff % 3600000) / 60000);
  const s = Math.floor((diff % 60000) / 1000);
  const pad = n => String(n).padStart(2,'0');
  const cdH = document.getElementById('cdH');
  const cdM = document.getElementById('cdM');
  const cdS = document.getElementById('cdS');
  if(cdH) cdH.textContent = pad(h);
  if(cdM) cdM.textContent = pad(m);
  if(cdS) cdS.textContent = pad(s);
  requestAnimationFrame(updateCountdown);
}
requestAnimationFrame(updateCountdown);
// ── COMPTEUR animé avec rAF (plus fluide que setInterval 16ms) ──
function animateCounter(el, target, duration) {
  const startTime = performance.now();
  function step(now) {
    const elapsed = now - startTime;
    const progress = Math.min(elapsed / duration, 1);
    el.textContent = Math.ceil(progress * target);
    if(progress < 1) requestAnimationFrame(step);
  }
  requestAnimationFrame(step);
}
// Compteur animé géré par Firebase loadCounters()
// ── MENU HAMBURGER ──
function toggleNav() {
  const nav = document.getElementById('navLinks');
  const btn = document.getElementById('hamburger');
  nav.classList.toggle('open');
  btn.classList.toggle('open');
}
function closeNav() {
  document.getElementById('navLinks').classList.remove('open');
  document.getElementById('hamburger').classList.remove('open');
}
renderReviews();
renderProducts();
updateCart();
// ── INTERSECTION OBSERVER : animations au scroll ──
if('IntersectionObserver' in window) {
  const observer = new IntersectionObserver((entries) => {
    entries.forEach(e => {
      if(e.isIntersecting) {
        e.target.style.animationPlayState = 'running';
        observer.unobserve(e.target);
      }
    });
  }, { threshold: 0.1 });
  // Pauser les animations hors écran (cards, avis)
  document.querySelectorAll('.review-card, .how-step, .about-card, .about-icon').forEach(el => {
    el.style.animationPlayState = 'paused';
    observer.observe(el);
  });
}


