// ── MÉMOIRE LOCALE — avec TTL et nettoyage ──
const OlaMemory = {
  // sessionStorage (vie de l'onglet)
  get(key) {
    try { return JSON.parse(sessionStorage.getItem('olabot_' + key)); } catch(e) { return null; }
  },
  set(key, val) {
    try { sessionStorage.setItem('olabot_' + key, JSON.stringify(val)); } catch(e) {}
  },
  del(key) {
    try { sessionStorage.removeItem('olabot_' + key); } catch(e) {}
  },
  // localStorage (persistant) avec TTL optionnel
  getLs(key) {
    try {
      const raw = localStorage.getItem('olabot_' + key);
      if (!raw) return null;
      const item = JSON.parse(raw);
      // Support TTL : { v: valeur, exp: timestamp }
      if (item && item.exp && Date.now() > item.exp) {
        localStorage.removeItem('olabot_' + key);
        return null;
      }
      return item && item.hasOwnProperty('v') ? item.v : item;
    } catch(e) { return null; }
  },
  setLs(key, val, ttlDays) {
    try {
      const item = ttlDays
        ? { v: val, exp: Date.now() + ttlDays * 86400000 }
        : { v: val };
      localStorage.setItem('olabot_' + key, JSON.stringify(item));
    } catch(e) {}
  },
  // Nettoyage des clés expirées et obsolètes
  cleanup() {
    try {
      const toRemove = [];
      for (let i = 0; i < localStorage.length; i++) {
        const k = localStorage.key(i);
        if (!k || !k.startsWith('olabot_')) continue;
        try {
          const raw = localStorage.getItem(k);
          const item = JSON.parse(raw);
          if (item && item.exp && Date.now() > item.exp) toRemove.push(k);
        } catch(e) { toRemove.push(k); }
      }
      toRemove.forEach(k => localStorage.removeItem(k));
    } catch(e) {}
  }
};
