  msgs.appendChild(typing);
  _autoScroll();
  // Délai proportionnel à la longueur (min 700ms, max 2000ms)
  const delay = Math.min(Math.max(700, text.split(' ').length * 35), 2000);
  setTimeout(() => {
    typing.remove();
    olabotIsTyping = false;
    _renderBotMsg(text, quickReplies || [], extraHTML || null);
  }, delay);
